import React, { useEffect, useRef, useState } from 'react';
import { Video, VideoOff, Mic, MicOff, PhoneOff } from 'lucide-react';
import { io } from 'socket.io-client';

const ICE_SERVERS = { iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] };

export default function VideoCall({ channelName, onEndCall }) {
    const localVideoRef  = useRef(null);
    const remoteVideoRef = useRef(null);
    const socketRef      = useRef(null);
    const pcRef          = useRef(null);
    const localStreamRef = useRef(null);

    const [hasVideo, setHasVideo]             = useState(true);
    const [hasAudio, setHasAudio]             = useState(true);
    const [error, setError]                   = useState('');
    const [remoteConnected, setRemoteConnected] = useState(false);
    const [messages, setMessages]             = useState([]);
    const [newMessage, setNewMessage]         = useState('');

    useEffect(() => {
        let isMounted = true;

        const setup = async () => {
            // 1. Get local media
            let stream;
            try {
                stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
                localStreamRef.current = stream;
                if (localVideoRef.current) localVideoRef.current.srcObject = stream;
            } catch (err) {
                if (isMounted) setError('Camera/Microphone access denied or unavailable.');
                return;
            }

            // 2. Connect to Socket.IO signaling server
            const socket = io('http://localhost:3004');
            socketRef.current = socket;

            // 3. Create RTCPeerConnection
            const pc = new RTCPeerConnection(ICE_SERVERS);
            pcRef.current = pc;

            // Add local tracks so remote peer receives them
            stream.getTracks().forEach(track => pc.addTrack(track, stream));

            // When remote stream arrives, show it
            pc.ontrack = (event) => {
                if (isMounted && remoteVideoRef.current) {
                    remoteVideoRef.current.srcObject = event.streams[0];
                    setRemoteConnected(true);
                }
            };

            // Send ICE candidates to the other peer via socket
            pc.onicecandidate = (event) => {
                if (event.candidate) {
                    socket.emit('ice-candidate', { roomId: channelName, candidate: event.candidate });
                }
            };

            // Chat messages
            socket.on('receive-message', (data) => {
                if (isMounted) setMessages(prev => [...prev, data]);
            });

            // Someone else is in the room â€” we are the CALLER, create offer
            socket.on('user-joined', async () => {
                try {
                    const offer = await pc.createOffer();
                    await pc.setLocalDescription(offer);
                    socket.emit('offer', { roomId: channelName, sdp: offer });
                } catch (e) { console.error('Error creating offer:', e); }
            });

            // We received an offer â€” we are the CALLEE, create answer
            socket.on('offer', async ({ sdp }) => {
                try {
                    await pc.setRemoteDescription(new RTCSessionDescription(sdp));
                    const answer = await pc.createAnswer();
                    await pc.setLocalDescription(answer);
                    socket.emit('answer', { roomId: channelName, sdp: answer });
                } catch (e) { console.error('Error handling offer:', e); }
            });

            // Caller receives the answer
            socket.on('answer', async ({ sdp }) => {
                try {
                    if (pc.signalingState !== 'stable') {
                        await pc.setRemoteDescription(new RTCSessionDescription(sdp));
                    }
                } catch (e) { console.error('Error handling answer:', e); }
            });

            // Add ICE candidates from peer
            socket.on('ice-candidate', async ({ candidate }) => {
                try {
                    if (candidate && pc.remoteDescription) {
                        await pc.addIceCandidate(new RTCIceCandidate(candidate));
                    }
                } catch (e) { console.error('Error adding ICE candidate:', e); }
            });

            // Join the room â€” this triggers 'user-joined' on any existing participant
            socket.emit('join-room', channelName);
        };

        setup();

        return () => {
            isMounted = false;
            if (localStreamRef.current) localStreamRef.current.getTracks().forEach(t => t.stop());
            if (pcRef.current) pcRef.current.close();
            if (socketRef.current) socketRef.current.disconnect();
        };
    }, [channelName]);

    const toggleVideo = () => {
        if (localStreamRef.current) {
            localStreamRef.current.getVideoTracks().forEach(t => { t.enabled = !t.enabled; });
            setHasVideo(v => !v);
        }
    };

    const toggleAudio = () => {
        if (localStreamRef.current) {
            localStreamRef.current.getAudioTracks().forEach(t => { t.enabled = !t.enabled; });
            setHasAudio(a => !a);
        }
    };

    const handleEndCall = () => {
        if (localStreamRef.current) localStreamRef.current.getTracks().forEach(t => t.stop());
        if (pcRef.current) pcRef.current.close();
        if (socketRef.current) socketRef.current.disconnect();
        if (onEndCall) onEndCall();
    };

    const sendMessage = (e) => {
        e.preventDefault();
        if (!newMessage.trim() || !socketRef.current) return;
        const msgData = {
            roomId: channelName,
            text: newMessage,
            time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            socketId: socketRef.current.id
        };
        socketRef.current.emit('send-message', msgData);
        setMessages(prev => [...prev, msgData]);
        setNewMessage('');
    };

    return (
        <div className="flex w-full h-[500px] bg-gray-900 rounded-2xl overflow-hidden shadow-2xl">
            {/* Video area */}
            <div className="relative flex-1 flex items-center justify-center bg-gray-900">
                {error ? (
                    <div className="text-white text-center">
                        <p className="text-xl mb-2">Could not start video call.</p>
                        <p className="text-gray-400">{error}</p>
                    </div>
                ) : (
                    <>
                        {/* Remote video (full area) */}
                        <div className="absolute inset-0 flex items-center justify-center bg-gray-800">
                            {remoteConnected ? (
                                <video ref={remoteVideoRef} autoPlay playsInline className="w-full h-full object-cover" />
                            ) : (
                                <div className="text-center text-gray-400">
                                    <Video className="w-16 h-16 mx-auto mb-4 opacity-50" />
                                    <p>Waiting for the other participant to join...</p>
                                    <p className="text-sm mt-2 text-gray-500">Channel: <span className="text-white font-bold">{channelName}</span></p>
                                </div>
                            )}
                        </div>

                        {/* Local video PiP */}
                        <div className="absolute bottom-6 right-6 w-48 h-36 bg-gray-950 rounded-xl overflow-hidden border-2 border-gray-700 shadow-2xl z-10">
                            {hasVideo ? (
                                <video ref={localVideoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
                            ) : (
                                <div className="w-full h-full flex items-center justify-center bg-gray-800">
                                    <VideoOff className="w-8 h-8 text-gray-500" />
                                </div>
                            )}
                        </div>

                        {/* Controls */}
                        <div className="absolute bottom-6 left-1/2 transform -translate-x-1/2 flex gap-4 bg-gray-900/80 backdrop-blur-md px-6 py-3 rounded-full border border-gray-700 z-10">
                            <button onClick={toggleAudio} className={`p-4 rounded-full transition outline-none ${hasAudio ? 'bg-gray-700 hover:bg-gray-600 text-white' : 'bg-red-500 hover:bg-red-600 text-white'}`}>
                                {hasAudio ? <Mic className="w-6 h-6" /> : <MicOff className="w-6 h-6" />}
                            </button>
                            <button onClick={toggleVideo} className={`p-4 rounded-full transition outline-none ${hasVideo ? 'bg-gray-700 hover:bg-gray-600 text-white' : 'bg-red-500 hover:bg-red-600 text-white'}`}>
                                {hasVideo ? <Video className="w-6 h-6" /> : <VideoOff className="w-6 h-6" />}
                            </button>
                            <button onClick={handleEndCall} className="p-4 rounded-full bg-red-600 hover:bg-red-700 text-white transition outline-none">
                                <PhoneOff className="w-6 h-6" />
                            </button>
                        </div>
                    </>
                )}
            </div>

            {/* Right side: Chat */}
            <div className="w-80 bg-gray-800 border-l border-gray-700 flex flex-col">
                <div className="p-4 border-b border-gray-700 bg-gray-900 font-medium text-white shadow z-10">
                    Live Chat
                </div>
                <div className="flex-1 p-4 overflow-y-auto space-y-3 flex flex-col">
                    {messages.length === 0 && <p className="text-gray-500 text-sm text-center mt-4">No messages yet</p>}
                    {messages.map((msg, idx) => {
                        const isMe = msg.socketId === socketRef.current?.id;
                        return (
                            <div key={idx} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                                <span className="text-[10px] text-gray-400 mb-1">{msg.time} {isMe ? '(You)' : ''}</span>
                                <div className={`px-4 py-2 rounded-xl text-sm max-w-[90%] break-words ${isMe ? 'bg-blue-600 text-white rounded-br-none' : 'bg-gray-700 text-gray-100 rounded-bl-none'}`}>
                                    {msg.text}
                                </div>
                            </div>
                        );
                    })}
                </div>
                <form onSubmit={sendMessage} className="p-4 border-t border-gray-700 bg-gray-900 flex gap-2">
                    <input type="text" value={newMessage} onChange={e => setNewMessage(e.target.value)} placeholder="Type message..." className="flex-1 px-3 py-2 bg-gray-800 text-white rounded-lg border border-gray-700 focus:ring-2 focus:ring-blue-500 outline-none text-sm placeholder-gray-500" />
                    <button type="submit" className="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700 transition outline-none">Send</button>
                </form>
            </div>
        </div>
    );
}
